/* ==========================================================================
   FICCC Design Tokens & Global Styles
   Palette: "Gathered Warmth" (D007)
   ========================================================================== */

/* --- Font imports (self-hosted via fontsource) --- */
@import '@fontsource-variable/lora';
@import '@fontsource-variable/inter';

/* ==========================================================================
   CSS Custom Properties
   ========================================================================== */

:root {
  /* --- Colors: Gathered Warmth palette --- */
  --color-bg:          #FAF8F5;  /* off-white background       */
  --color-stone:       #E8E0D8;  /* warm stone / borders        */
  --color-terracotta:  #C4745A;  /* muted terracotta / accent   */
  --color-ink:         #1A1A2E;  /* deep ink / headings         */
  --color-body:        #2D2D2D;  /* body text                   */

  /* --- Spacing: 4px base scale --- */
  --space-1:    4px;   /*  4 */
  --space-2:    8px;   /*  8 */
  --space-3:   12px;   /* 12 */
  --space-4:   16px;   /* 16 */
  --space-6:   24px;   /* 24 */
  --space-8:   32px;   /* 32 */
  --space-12:  48px;   /* 48 */
  --space-16:  64px;   /* 64 */
  --space-24:  96px;   /* 96 */
  --space-32: 128px;   /* 128 */

  /* --- Font families --- */
  --font-heading:  'Lora Variable', 'Noto Serif SC', Georgia, serif;
  --font-body:     'Inter Variable', 'Noto Serif SC', system-ui, sans-serif;
  --font-cjk:      'Noto Serif SC', 'Lora Variable', serif;

  /* --- Type scale (EN) — modular, ~1.25 ratio --- */
  --text-xs:     0.75rem;   /* 12px */
  --text-sm:     0.875rem;  /* 14px */
  --text-base:   1rem;      /* 16px */
  --text-lg:     1.25rem;   /* 20px */
  --text-xl:     1.5rem;    /* 24px */
  --text-2xl:    2rem;      /* 32px */
  --text-3xl:    2.5rem;    /* 40px */
  --text-4xl:    3rem;      /* 48px */

  /* --- Line heights --- */
  --leading-tight:   1.25;
  --leading-normal:  1.5;
  --leading-relaxed: 1.65;
  --leading-cjk:     1.75;

  /* --- Type scale (ZH) — slightly larger base for readability --- */
  --text-zh-base:  1.125rem;  /* 18px */
  --text-zh-lg:    1.375rem;  /* 22px */
  --text-zh-xl:    1.625rem;  /* 26px */
  --text-zh-2xl:   2.125rem;  /* 34px */
  --text-zh-3xl:   2.625rem;  /* 42px */

  /* --- Layout --- */
  --max-width:  72rem;

  /* --- Misc --- */
  --radius-sm:  4px;
  --radius-md:  8px;
  --radius-lg: 16px;
  --transition: 200ms ease;
  --color-focus: var(--color-terracotta);
  --color-bg-dark: #1A1A2E;       /* deep ink — used for footer bg */
}

/* ==========================================================================
   Minimal Reset
   ========================================================================== */

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  -webkit-text-size-adjust: 100%;
  -moz-text-size-adjust: 100%;
  text-size-adjust: 100%;
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-body);
  font-size: var(--text-base);
  line-height: var(--leading-normal);
  color: var(--color-body);
  background-color: var(--color-bg);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

img,
picture,
video,
canvas,
svg {
  display: block;
  max-width: 100%;
}

input,
button,
textarea,
select {
  font: inherit;
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-heading);
  color: var(--color-ink);
  line-height: var(--leading-tight);
  text-wrap: balance;
}

p {
  text-wrap: pretty;
}

a {
  color: var(--color-terracotta);
  text-decoration-skip-ink: auto;
}

/* --- CJK utility --- */
:lang(zh) {
  font-family: var(--font-cjk);
  line-height: var(--leading-cjk);
}

arguments.content:
---
interface Props {
  title: string;
  subtitle?: string;
  ctaText?: string;
  ctaHref?: string;
  backgroundImage: string;
}

const { title, subtitle, ctaText, ctaHref, backgroundImage } = Astro.props;
---

<section
  class="hero"
  style={`background-image: url('${backgroundImage}');`}
>
  <div class="hero__overlay">
    <div class="hero__content">
      <h1 class="hero__title">{title}</h1>
      {subtitle && <p class="hero__subtitle">{subtitle}</p>}
      {ctaText && ctaHref && (
        <a class="hero__cta" href={ctaHref}>{ctaText}</a>
      )}
    </div>
  </div>
</section>

<style>
  .hero {
    width: 100%;
    min-height: 28rem;
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .hero__overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(
      to bottom,
      rgba(26, 26, 46, 0.55) 0%,
      rgba(26, 26, 46, 0.72) 100%
    );
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .hero__content {
    position: relative;
    text-align: center;
    max-width: var(--max-width);
    padding: var(--space-12) var(--space-6);
    color: var(--color-bg);
  }

  .hero__title {
    font-family: var(--font-heading);
    font-size: var(--text-4xl);
    line-height: var(--leading-tight);
    color: var(--color-bg);
    margin-block-end: var(--space-4);
  }

  .hero__subtitle {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-stone);
    max-width: 36rem;
    margin-inline: auto;
    margin-block-end: var(--space-8);
  }

  .hero__cta {
    display: inline-block;
    font-family: var(--font-body);
    font-size: var(--text-base);
    font-weight: 600;
    color: var(--color-bg);
    background-color: var(--color-terracotta);
    padding: var(--space-3) var(--space-8);
    border-radius: var(--radius-md);
    text-decoration: none;
    transition: background-color var(--transition), transform var(--transition);
  }

  .hero__cta:hover {
    background-color: #b3654b;
    transform: translateY(-1px);
  }

  .hero__cta:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  @media (max-width: 768px) {
    .hero {
      min-height: 22rem;
    }

    .hero__title {
      font-size: var(--text-2xl);
    }

    .hero__subtitle {
      font-size: var(--text-base);
    }

    .hero__content {
      padding: var(--space-8) var(--space-4);
    }
  }
</style>

---
interface Props {
  title: string;
  body?: string;
  image?: string;
  href?: string;
}

const { title, body, image, href } = Astro.props;
const Tag = href ? 'a' : 'div';
---

<Tag class="card" {...(href ? { href } : {})}>
  {image && (
    <div class="card__image-wrap">
      <img class="card__image" src={image} alt="" loading="lazy" />
    </div>
  )}
  <div class="card__body">
    <h3 class="card__title">{title}</h3>
    {body && <p class="card__text">{body}</p>}
  </div>
</Tag>

<style>
  .card {
    display: flex;
    flex-direction: column;
    border-radius: var(--radius-md);
    border: 1px solid var(--color-stone);
    background-color: var(--color-bg);
    overflow: hidden;
    text-decoration: none;
    color: inherit;
    transition: box-shadow var(--transition), transform var(--transition);
  }

  a.card:hover {
    box-shadow: 0 4px 16px rgba(26, 26, 46, 0.1);
    transform: translateY(-2px);
  }

  a.card:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  .card__image-wrap {
    aspect-ratio: 3 / 2;
    overflow: hidden;
  }

  .card__image {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .card__body {
    padding: var(--space-6);
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
  }

  .card__title {
    font-family: var(--font-heading);
    font-size: var(--text-lg);
    line-height: var(--leading-tight);
    color: var(--color-ink);
  }

  .card__text {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }
</style>

---
interface Props {
  images: { src: string; alt: string }[];
}

const { images } = Astro.props;
---

<div class="mosaic">
  {images.map((img, i) => (
    <figure class={`mosaic__cell mosaic__cell--${(i % 6) + 1}`}>
      <img
        class="mosaic__img"
        src={img.src}
        alt={img.alt}
        loading="lazy"
      />
    </figure>
  ))}
</div>

<style>
  .mosaic {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: var(--space-3);
  }

  .mosaic__cell {
    overflow: hidden;
    border-radius: var(--radius-md);
  }

  /* Vary cell sizes for visual interest */
  .mosaic__cell--1 {
    grid-column: span 2;
    grid-row: span 2;
  }

  .mosaic__cell--4 {
    grid-column: span 2;
  }

  .mosaic__img {
    width: 100%;
    height: 100%;
    aspect-ratio: 4 / 3;
    object-fit: cover;
    display: block;
  }

  /* Spanned cells get different ratios */
  .mosaic__cell--1 .mosaic__img {
    aspect-ratio: 1;
  }

  .mosaic__cell--4 .mosaic__img {
    aspect-ratio: 2 / 1;
  }

  @media (max-width: 1024px) {
    .mosaic {
      grid-template-columns: repeat(2, 1fr);
    }

    .mosaic__cell--1 {
      grid-column: span 2;
      grid-row: span 1;
    }

    .mosaic__cell--1 .mosaic__img {
      aspect-ratio: 2 / 1;
    }

    .mosaic__cell--4 {
      grid-column: span 1;
    }
  }

  @media (max-width: 640px) {
    .mosaic {
      grid-template-columns: 1fr;
    }

    .mosaic__cell--1,
    .mosaic__cell--4 {
      grid-column: span 1;
    }

    .mosaic__img {
      aspect-ratio: 16 / 9;
    }

    .mosaic__cell--1 .mosaic__img,
    .mosaic__cell--4 .mosaic__img {
      aspect-ratio: 16 / 9;
    }
  }
</style>

